    business.website || '';

  const pageType = original.page_type || j.page_type || 'seite';
  const isStart  = original.is_start === true || j.is_start === true || pageType === 'startseite';

  let content =
    (apifyItem ? apifyItem.html : null) ||
    j.results?.[0]?.content ||
    j.html || j.data || j.body || '';

  if (typeof content !== 'string') content = JSON.stringify(content || '');
  if (isStart && pageUrl) final_url = pageUrl;
  if (pageUrl) crawled_urls.push(pageUrl);

  if (content && content.length > 100) {
    combined += `\n<!-- SEITE: ${pageType} (${pageUrl}) -->\n${content}`;
  } else {
    warnings.push(`empty_content_${pageType}`);
  }
}

if (!final_url) final_url = business.website || crawled_urls[0] || '';

return [{ json: {
  lead_id, score, business, final_url,
  crawled_urls: [...new Set(crawled_urls)],
  html: combined, html_length: combined.length,
  pages_collected: crawled_urls.length, warnings
} }];

// Extract images from Apify Google Maps response
// n8n may split the array, so $json could be the place object directly OR an array
const resp = $json;

let lead_id, score, business;
try {
  lead_id  = $('Loop je Lead').item.json.lead_id  || '';
  score    = $('Loop je Lead').item.json.score    || 0;
  business = $('Loop je Lead').item.json.business || {};
} catch(e) {
  // Fallback if Loop je Lead not accessible
  lead_id  = resp.searchString ? '' : (resp.placeId || '');
  score    = 0;
  business = {};
}

// Handle both: array (not split) or object (n8n split it)
let place = {};
if (Array.isArray(resp) && resp.length > 0) {
  place = resp[0];
} else if (resp && typeof resp === 'object' && !Array.isArray(resp)) {
  place = resp;  // n8n split the array; $json is already the place object
}

// Extract image URLs
let imageUrls = [];
if (Array.isArray(place.imageUrls) && place.imageUrls.length > 0) {
  imageUrls = place.imageUrls;
} else if (Array.isArray(place.images) && place.images.length > 0) {
  imageUrls = place.images.map(img =>
    typeof img === 'string' ? img : (img.imageUrl || img.url || img.src || '')
  ).filter(Boolean);
} else if (Array.isArray(place.photos) && place.photos.length > 0) {
  imageUrls = place.photos.map(p =>
    typeof p === 'string' ? p : (p.url || p.imageUrl || p.src || '')
  ).filter(Boolean);
}

const final_url = place.url || place.website || business.website || '';

// Build candidates in standard format (same as old HTML extractor)
const candidates = imageUrls.slice(0, 15).map((url, idx) => ({
  url: String(url),
  source: 'google_maps',
  alt: (place.title || business.name || '') + ' photo ' + (idx + 1),
  is_logo_hint: false,
  priority_hint: idx === 0 ? 'hero' : '',
  w: 0, h: 0
}));

return {
  lead_id,
  score,
  business,
  final_url,
  candidates_total: imageUrls.length,
  candidates_kept: candidates.length,
  candidates
};

const inputItems = $input.all();

if (!inputItems.length) {
  return [{
    json: {
      no_candidates: true,
      warnings: ['split_no_input_items']
    }
  }];
}

// Normalerweise kommt hier genau 1 Item von "Bild-Kandidaten"
const s = inputItems[0].json || {};
const candidates = Array.isArray(s.candidates) ? s.candidates : [];

const extras = {
  lead_id: s.lead_id || '',
  final_url: s.final_url || '',
  candidates_total: s.candidates_total || candidates.length,
  candidates_kept: s.candidates_kept || candidates.length,
  score: s.score || 0,
  business: s.business || {},
};

// Wenn keine Bilder gefunden wurden, NICHT still sterben
if (!candidates.length) {
  return [{
    json: {
      ...extras,
      idx: 0,
      url: '',
      source: 'none',
      is_logo_hint: false,
      alt: '',
      no_candidates: true,
      warnings: ['no_image_candidates']
    }
  }];
}

// Aus jedem Kandidaten ein eigenes Item machen
return candidates.map((c, idx) => ({
  json: {
    ...extras,
    idx,
    url: c.url || '',
    source: c.source || '',
    is_logo_hint: !!c.is_logo_hint,
    alt: c.alt || '',
    priority_hint: c.priority_hint || '',
    w: c.w || null,
    h: c.h || null,
    no_candidates: false
  }
}));

const items = $input.all();
if (!items.length) return [];

const first = items[0].json;
const candSet = {
  lead_id:         first.lead_id         || '',
  score:           first.score           || 0,
  business:        first.business        || {},
  final_url:       first.final_url       || '',
  candidates_total: first.candidates_total || items.length,
};

const content = [{ type: 'text', text:
  'Bilder von Google Maps fuer: ' + (candSet.business?.name || candSet.lead_id) +
  '\nURLs in Reihenfolge:\n' +
  items.map((it,i) => `#${i+1}: ${it.json.url}`).join('\n') +
  '\nBeurteile jedes Bild gemaess Schema. Nutze exakt diese URLs.' }];

let count = 0;
for (let i = 0; i < items.length && count < 12; i++) {
  const it = items[i];
  const imgUrl = it.json.url || '';

  // Strategy 1: Read binary via n8n helper (handles filesystem binaryMode)
  if (it.binary && it.binary.data) {
    const mime = it.binary.data.mimeType || 'image/jpeg';
    if (/^image\//.test(mime)) {
      try {
        const buffer = await $helpers.getBinaryDataBuffer(it, 'data');
        const b64 = buffer.toString('base64');
        content.push({ type: 'image_url', image_url: { url: `data:${mime};base64,${b64}` } });
        count++;
        continue;
      } catch(e) {
        // Fall through to URL strategy
      }
    }
  }

  // Strategy 2: Send image URL directly (Google Maps CDN works with Claude Vision)
  if (imgUrl && /^https?:\/\//.test(imgUrl)) {
    content.push({ type: 'image_url', image_url: { url: imgUrl } });
    count++;
  }
}

return [{ json: {
  lead_id:          candSet.lead_id,
  score:            candSet.score,
  business:         candSet.business,
  final_url:        candSet.final_url,
  candidates_total: candSet.candidates_total,
  vision_messages:  content,
  image_count:      count,
} }];

// ─── Get Vision response (bypass empty Set node) ───
let visionResp = $json;
// If empty Set node cleared $json, access Vision node directly
if (!visionResp?.choices && !visionResp?.content) {
  try { visionResp = $('Vision (Poe Sonnet)').first().json; } catch(e) {}
}

// ─── Get candidate set from Vision-Input bauen + Bild-Kandidaten ───
let candSet = { lead_id: '', score: 0, business: {}, final_url: '', candidates_total: 0, candidates: [] };
try {
  const vInput = $('Vision-Input bauen').first().json;
  candSet.lead_id   = vInput.lead_id   || '';
  candSet.score     = vInput.score     || 0;
  candSet.business  = vInput.business  || {};
  candSet.final_url = vInput.final_url || '';
  candSet.candidates_total = vInput.candidates_total || 0;
  try { candSet.candidates = $('Bild-Kandidaten').first().json.candidates || []; } catch(_) {}
} catch(e) {}

const warnings = [];

function parseLLM(resp) {
  try {
    let c = resp?.choices?.[0]?.message?.content || resp?.content || '';
    c = String(c).trim();
    // Strip markdown code blocks
    c = c.replace(/^```(?:json)?\s*/im, '').replace(/\s*```\s*$/im, '').trim();
    // Find JSON object
    const m = c.match(/\{[\s\S]*\}/);
    if (m) {
      try { return JSON.parse(m[0]); } catch(e2) {
        // Try repair: close unclosed arrays/objects
        let s = m[0];
        const opens = (s.match(/\[/g)||[]).length - (s.match(/\]/g)||[]).length;
        const openBraces = (s.match(/\{/g)||[]).length - (s.match(/\}/g)||[]).length;
        for (let i=0;i<opens;i++) s += ']';
        for (let i=0;i<openBraces;i++) s += '}';
        try { return JSON.parse(s); } catch(e3) {}
      }
    }
    return JSON.parse(c);
  } catch(e) { return null; }
}

let v = parseLLM(visionResp);
if (!v) { warnings.push('vision_parse_failed'); v = {}; }

const cands = candSet.candidates || [];
const logoHint  = cands.find(c => c.is_logo_hint) || null;
const logoFromV = v.logo?.url && v.logo.url !== 'keins' ? v.logo : null;
const logoUrl   = logoFromV?.url || logoHint?.url || '';
const logo = {
  url: logoUrl, local_path: '', format: logoUrl.endsWith('.svg')?'svg':'png',
  width:0, height:0, is_vector:logoUrl.endsWith('.svg'),
  qualitaet: logoFromV?.qualitaet||(logoHint?'niedrig':'keins'),
  begruendung: logoFromV?.begruendung||'',
};

const heroUrl = (v.hero?.url && v.hero.url !== 'keins') ? v.hero.url : '';
const hero = { url:heroUrl, local_path:'', width:0, height:0, qualitaet_score:v.hero?.qualitaet_score||0, begruendung:v.hero?.begruendung||'' };

const bilderLLM = Array.isArray(v.bilder) ? v.bilder : [];
const assets = bilderLLM.map(b=>({
  url:b.url||'', local_path:'', width:0, height:0, file_size:0, mime_type:'',
  aspect_ratio:0,
  source_url:candSet.final_url||'', category:b.kategorie||'sonstiges',
  quality_score:b.qualitaet_score||0,
  usage_recommendation:b.eignung==='verwenden'?'verwenden':b.eignung==='mit_vorbehalt'?'mit_vorbehalt':'nicht_verwenden',
  begruendung:b.begruendung||'',
}));
const verwendbare = assets.filter(a=>a.usage_recommendation!=='nicht_verwenden');
const fehlende = [];
const cats = bilderLLM.map(b=>b.kategorie||'');
if(!hero.url)                         fehlende.push('kein_gutes_hero');
if(logo.qualitaet==='keins')          fehlende.push('logo_nur_favicon');
if(!cats.includes('food'))            fehlende.push('keine_food_bilder');
if(!cats.some(c=>c==='interieur'))    fehlende.push('keine_innenraum_bilder');
if(!cats.includes('team'))            fehlende.push('keine_team_bilder');
const stats = { kandidaten_gesamt:candSet.candidates_total||cands.length, geladen:0, verwendbar:verwendbare.length, gespeichert:0 };
let conf = 1.0;
if(warnings.includes('vision_parse_failed')) conf-=0.40;
if(stats.geladen===0) conf-=0.30;
conf = Math.round(Math.max(0.1,Math.min(1.0,conf))*100)/100;
const manifest = {
  schema_version:'2.0', agent:'image_extractor', lead_id:candSet.lead_id||'',
  source_url:candSet.final_url||'', crawled_urls:[], generated_at:new Date().toISOString(),
  logo, hero, assets, farbpalette:Array.isArray(v.farbpalette)?v.farbpalette:[],
  bild_stil:v.bild_stil||'', konzept_text:v.konzept_text||'',
  empfehlung_agent5:v.empfehlung_agent4||v.empfehlung_agent5||'',
  fehlende_assets:fehlende, stats, confidence:conf, warnings,
  logs:[{ts:new Date().toISOString(),step:'manifest_complete',status:'ok'}],
};
try {
  const fs=require('fs');const dir=`/files/runs/${candSet.lead_id}`;
  if(candSet.lead_id){fs.mkdirSync(dir,{recursive:true});fs.writeFileSync(`${dir}/images.json`,JSON.stringify(manifest,null,2),'utf8');}
} catch(e) { manifest.warnings.push('file_write_failed'); }
return manifest;

// Normalize Apify response to Oxylabs-compatible format
const resp = $json;
let html = '', url = '';
if (Array.isArray(resp) && resp.length > 0) {
  html = resp[0].html || '';
  url = resp[0].url || resp[0].loadedUrl || '';
} else if (resp && typeof resp === 'object') {
  html = resp.results?.[0]?.content || resp.html || '';
  url = resp.results?.[0]?.url || resp.url || '';
}
return [{ json: { results: [{ content: html, url: url }] } }];
